import{_ as s,c as t,o as l,a4 as a}from"./chunks/framework.BxjRYGQi.js";const g=JSON.parse('{"title":"使用离线轨迹文件控制机器人运动","description":"","frontmatter":{},"headers":[],"relativePath":"zh/02-quick-start/10-offline-trajectory.md","filePath":"zh/02-quick-start/10-offline-trajectory.md"}'),e={name:"zh/02-quick-start/10-offline-trajectory.md"};function n(r,i,o,h,d,k){return l(),t("div",{"data-pagefind-body":!0},i[0]||(i[0]=[a(`<h1 id="使用离线轨迹文件控制机器人运动" tabindex="-1">使用离线轨迹文件控制机器人运动 <a class="header-anchor" href="#使用离线轨迹文件控制机器人运动" aria-label="Permalink to “使用离线轨迹文件控制机器人运动”">​</a></h1><p>离线轨迹可以实现更加精细的机器人运动，可用于更加复杂应用场景。</p><h2 id="准备离线轨迹文件" tabindex="-1">准备离线轨迹文件 <a class="header-anchor" href="#准备离线轨迹文件" aria-label="Permalink to “准备离线轨迹文件”">​</a></h2><p>离线轨迹文件为 CSV 格式，表头如下：</p><div class="language-csv"><button title="Copy Code" class="copy"></button><span class="lang">csv</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ts,</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">pts_J1,</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pts_J2,</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">pts_J3,</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">pts_J4,</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">pts_J5,</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">pts_J6,</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vel_J1,</span><span style="--shiki-light:#24292E;--shiki-light-font-weight:bold;--shiki-dark:#E1E4E8;--shiki-dark-font-weight:bold;">vel_J2,</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">vel_J3,vel_J4,</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">vel_J5,</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vel_J6,</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">acc_J1,</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">acc_J2,</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">acc_J3,</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">acc_J4,</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">acc_J5,</span><span style="--shiki-light:#24292E;--shiki-light-font-weight:bold;--shiki-dark:#E1E4E8;--shiki-dark-font-weight:bold;">acc_J6,</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">jerk_J1,jerk_J2,</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">jerk_J3,</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">jerk_J4,</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">jerk_J5,</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">jerk_J6,</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">do_port,</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">do_state</span></span></code></pre></div><h2 id="轨迹文件格式说明" tabindex="-1">轨迹文件格式说明 <a class="header-anchor" href="#轨迹文件格式说明" aria-label="Permalink to “轨迹文件格式说明”">​</a></h2><p><strong>1. <code>ts</code> （时间戳）</strong></p><ul><li><strong>含义</strong>：表示当前轨迹点的时间信息，通常以秒（s）为单位。</li><li><strong>作用</strong>：用于同步机械臂的运动时间，确保各关节在指定时间点达到目标位置、速度和加速度。</li></ul><p><strong>2. <code>pts_J1</code> 到 <code>pts_J6</code> （关节位置）</strong></p><ul><li><strong>含义</strong>： <ul><li><code>pts_J1</code> 到 <code>pts_J6</code> 分别表示机械臂的 <strong>6 个关节的位置（Joint Position）</strong>。</li><li>角度（单位：弧度，rad）</li></ul></li><li><strong>作用</strong>： <ul><li>定义机械臂末端执行器的空间位置和姿态（通过正运动学计算）。</li><li>是轨迹规划的核心数据，描述机械臂从起点到终点的路径。</li></ul></li></ul><p><strong>3. <code>vel_J1</code> 到 <code>vel_J6</code> （关节速度）</strong></p><ul><li><strong>含义</strong>： <ul><li><code>vel_J1</code> 到 <code>vel_J6</code> 分别表示机械臂 <strong>6 个关节的速度（Joint Velocity）</strong>。</li><li>单位是 <strong>弧度 / 秒（rad/s）</strong></li></ul></li><li><strong>作用</strong>： <ul><li>控制机械臂各关节的运动速度，确保末端执行器沿规划路径平稳移动。</li><li>避免因速度突变导致的机械冲击或振动。</li></ul></li></ul><p><strong>4. <code>acc_J1</code> 到 <code>acc_J6</code> （关节加速度）</strong></p><ul><li><strong>含义</strong>： <ul><li><code>acc_J1</code> 到 <code>acc_J6</code> 分别表示机械臂 <strong>6 个关节的加速度（Joint Acceleration）</strong>。</li><li>单位是 <strong>弧度 / 秒 ²（rad/s²）</strong></li></ul></li><li><strong>作用</strong>： <ul><li>描述关节速度的变化率，影响机械臂的动态性能。</li><li>过高的加速度可能导致机械臂超载或产生不必要的振动。</li></ul></li></ul><p><strong>5. <code>jerk_J1</code> 到 <code>jerk_J6</code> （关节加加速度）</strong></p><ul><li><strong>含义</strong>： <ul><li><code>jerk_J1</code> 到 <code>jerk_J6</code> 分别表示机械臂 <strong>6 个关节的加加速度（Joint Jerk）</strong>。</li><li>单位通常是 <strong>弧度 / 秒 ³（rad/s³）</strong></li></ul></li><li><strong>作用</strong>： <ul><li>描述加速度的变化率，直接影响机械臂运动的平滑性。</li></ul></li></ul><p><strong>6. <code>do_port</code> （数字输出端口）</strong></p><ul><li><strong>含义</strong>： <ul><li>表示机械臂的 <strong>数字输出端口（Digital Output Port）</strong> 编号。</li><li>通常用于控制外部设备（如夹爪、吸盘、传感器等）。</li></ul></li><li><strong>作用</strong>： <ul><li>在特定时间点触发外部设备的开关状态（例如夹爪的抓取或释放）。</li></ul></li></ul><p><strong>7. <code>do_state</code> （数字输出状态）</strong></p><ul><li><strong>含义</strong>： <ul><li>表示数字输出端口（ <code>do_port</code> ）的 <strong>状态（State）</strong>，通常为布尔值（0 或 1）。</li><li>例如： <ul><li><code>0</code> 表示关闭（如夹爪松开）。</li><li><code>1</code> 表示开启（如夹爪闭合）。</li></ul></li></ul></li><li><strong>作用</strong>： <ul><li>协调机械臂运动与外部设备的联动（例如在机械臂到达目标位置后触发夹爪抓取）。</li></ul></li></ul><h2 id="使用说明" tabindex="-1">使用说明 <a class="header-anchor" href="#使用说明" aria-label="Permalink to “使用说明”">​</a></h2><p><strong>设置机器人 IP</strong><code>gbt_driver/config/robot_config.yaml</code> 中设置 <code>robot_ip_address</code> 为机器人 IP 地址</p><h3 id="启动服务" tabindex="-1">启动服务 <a class="header-anchor" href="#启动服务" aria-label="Permalink to “启动服务”">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">source</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install/setup.bash</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ros2</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ros2</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> launch</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gbt_offline_trajectory.launch.py</span></span></code></pre></div><h3 id="接口使用示例" tabindex="-1">接口使用示例 <a class="header-anchor" href="#接口使用示例" aria-label="Permalink to “接口使用示例”">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ros2</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> action</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> send_goal</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gbt_driver/trajectory</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gbt_interface/action/OfflineTrajectory</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;{trajectory_path: &#39;/home/gbt/tmp/src/Agilebot_Robot_Ros2/gbt_driver/test.csv&#39;}&quot;</span></span></code></pre></div>`,26)]))}const c=s(e,[["render",n]]);export{g as __pageData,c as default};
